9	const BASE_PREMIUM_BY_TYPE: Record<string, number> = {
10	  sword: 100,
11	  amulet: 60,
12	  staff: 80,
13	  potion: 40,
14	  rune: 25,
15	  moonstone: 25,
16	};
17	
18	const basePremiumFor = (item: Item): number => BASE_PREMIUM_BY_TYPE[item.type] ?? 0;
19	
20	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
21	const COMPONENT_BLOCK_SIZE = 3;
22	const COMPONENT_BLOCK_PRICE = 60;
23	const COMPONENT_UNIT_PRICE = 25;
24	
25	const isComponent = (item: Item): boolean => COMPONENT_TYPES.has(item.type);
26	
27	const roundPremium = (amount: number): number => Math.ceil(amount);
28	
29	const priceForComponentCount = (count: number): number =>
30	  count === COMPONENT_BLOCK_SIZE ? COMPONENT_BLOCK_PRICE : count * COMPONENT_UNIT_PRICE;
31	
32	const sumComponentBase = (componentCountsByType: Map<string, number>): number => {
33	  let total = 0;
34	  for (const count of componentCountsByType.values()) {
35	    total += priceForComponentCount(count);
36	  }
37	  return total;
38	};
39	
40	const baseForItems = (items: Item[]): number => {
41	  const componentCountsByType = new Map<string, number>();
42	  let nonComponentBase = 0;
43	  for (const item of items) {
44	    if (isComponent(item)) {
45	      componentCountsByType.set(item.type, (componentCountsByType.get(item.type) ?? 0) + 1);
46	    } else {
47	      nonComponentBase += basePremiumFor(item);
48	    }
49	  }
50	  return nonComponentBase + sumComponentBase(componentCountsByType);
51	};
52	
53	const curseSurchargeFor = (item: Item): number =>
54	  item.cursed ? basePremiumFor(item) * CURSE_RATE : 0;
55	
56	const itemModifiersFor = (items: Item[]): number => {
57	  let total = 0;
58	  for (const item of items) {
59	    total += curseSurchargeFor(item);
60	  }
61	  return total;
62	};
63	
64	const quotePremium = (items: Item[]): number => {
65	  const base = baseForItems(items);
66	  const itemModifiers = itemModifiersFor(items);
67	  const firstInsuranceSurcharge = base * FIRST_INSURANCE_RATE;
68	  return roundPremium(base + itemModifiers + firstInsuranceSurcharge + PROCESSING_FEE);
69	};
70	
71	export const runScenario = (input: {
72	  customer: { yearsWithMHPCO: number };
73	  steps: Step[];
74	}): { results: Result[] } => {
75	  const results = input.steps.map((step) => ({ premium: quotePremium(step.items) }));
76	  return { results };
77	};
